import{_ as u,r as n,o as p,c,a as e,b as t,t as l,d as o,w as h,e as r}from"./app-d223f2a5.js";const w={},m={id:"frontmatter-title-관련",tabindex:"-1"},f=e("a",{class:"header-anchor",href:"#frontmatter-title-관련","aria-hidden":"true"},"#",-1),y={class:"table-of-contents"},_=r('<hr><h2 id="project-15-part-two" tabindex="-1"><a class="header-anchor" href="#project-15-part-two" aria-hidden="true">#</a> Project 15, part two</h2><p>I hope you can agree that animation in iOS is almost invisible – we just lay out all the changes we want to happen, and Core Animation figures out all the intermediate steps to make it happen.</p><p>As I’ve said several times, animation is more than about making our software look good – it has a functional purpose too, ensuring that users understand why things and changing and what states they are moving from and to.</p><p>Larry Niven once said, “that&#39;s the thing about people who think they hate computers – what they really hate is lousy programmers.” Folks paid a lot of money for their iPhones and iPads, and Apple’s software oozes polish and refinement – if you don’t put a similar level of care into your own code then your app will stick out, and not in a good way.</p><p>So, with today’s challenges you need to apply your new animation knowledge to the projects you’ve made previously. I think you’ll be pleased how easy it is, and I hope also inspired to take on more animations in the future!</p><p><strong>Today you should work through the wrap up chapter for project 15, complete its review, then work through all three of its challenges.</strong></p><h3 id="wrap-up" tabindex="-1"><a class="header-anchor" href="#wrap-up" aria-hidden="true">#</a> Wrap up</h3>',8),g={class:"hint-container details"},k=e("summary",null,"Wrap up",-1),b={href:"https://www.hackingwithswift.com/read/15/5/wrap-up",target:"_blank",rel:"noopener noreferrer"},v=r('<p>Core Animation is an extraordinary toolkit, and UIKit wraps it in a simple and flexible set of methods. And because it&#39;s so simple to use, you really have no excuse for not using it.</p><p>In this project you learned about the <code>animate(withDuration:)</code> method of <code>UIView</code>, spring animations, as well as alpha values and <code>CGAffineTransform</code>.</p><p>Remember, animation isn’t just there to make our apps look pretty – it also helps guide the users eyes. So, if you&#39;re moving something around conceptually (e.g., moving an email to a folder, showing a palette of paint brushes, rolling a dice, etc) then move it around <em>visually</em> too. Your users will thank you for it!</p><h4 id="review-what-you-learned" tabindex="-1"><a class="header-anchor" href="#review-what-you-learned" aria-hidden="true">#</a> Review what you learned</h4><p>Anyone can sit through a tutorial, but it takes actual work to remember what was taught. It’s my job to make sure you take as much from these tutorials as possible, so I’ve prepared a short review to help you check your learning.</p>',5),j={href:"https://www.hackingwithswift.com/review/hws/project-15-animation",target:"_blank",rel:"noopener noreferrer"},x=r('<h4 id="challenge" tabindex="-1"><a class="header-anchor" href="#challenge" aria-hidden="true">#</a> Challenge</h4><p>One of the best ways to learn is to write your own code as often as possible, so here are three ways you should try your new knowledge to make sure you fully understand what’s going on:</p><ol><li>Go back to project 8 and make the letter group buttons fade out when they are tapped. We were using the <code>isHidden</code> property, but you&#39;ll need to switch to <code>alpha</code> because <code>isHidden</code> is either true or false, it has no animatable values between.</li><li>Go back to project 13 and make the image view fade in when a new picture is chosen. To make this work, set the <code>alpha</code> to 0 first.</li><li>Go back to project 2 and make the flags scale down with a little bounce when pressed.</li></ol>',3),I={class:"hint-container info"},A=e("p",{class:"hint-container-title"},"Wrap up - Additional",-1),C={href:"https://www.hackingwithswift.com/review/hws/project-15-animation",target:"_blank",rel:"noopener noreferrer"},T=e("p",null,"That’s another project finished, and one that sets you up to use animation at will in the future – post some videos online to show folks your creations!",-1);function W(i,N){const s=n("router-link"),a=n("ExternalLinkIcon"),d=n("YouTube");return p(),c("div",null,[e("h1",m,[f,t(" "+l(i.$frontmatter.title)+" 관련",1)]),e("blockquote",null,[e("p",null,l(i.$frontmatter.description),1)]),e("nav",y,[e("ul",null,[e("li",null,[o(s,{to:"#project-15-part-two"},{default:h(()=>[t("Project 15, part two")]),_:1}),e("ul",null,[e("li",null,[o(s,{to:"#wrap-up"},{default:h(()=>[t("Wrap up")]),_:1})])])])])]),_,e("details",g,[k,e("p",null,[e("a",b,[t("📎link"),o(a)])]),o(d,{id:"zqbWsKHkg74"}),v,e("p",null,[e("a",j,[t("Click here to review what you learned in project 15."),o(a)])]),x]),e("div",I,[A,e("p",null,[e("a",C,[t("Review for Project 15: Animation"),o(a)])])]),T])}const S=u(w,[["render",W],["__file","58.html.vue"]]);export{S as default};
